const mappingByItemDescription = new Map();
const bucketList = [];
const seenBuckets = new Set();
const seenSubstrates = new Set();
const categoriesBySubstrate = new Map();

SUBSTRATE_EXCEL_MAPPINGS.forEach((row) => {
  const itemKey = normalizeMappingText(row.itemDescription);
  if (itemKey && !mappingByItemDescription.has(itemKey)) {
    mappingByItemDescription.set(itemKey, row);
  }

  const bucketKey = `${normalizeMappingText(row.substrate)}::${normalizeMappingText(row.categoryDescription)}`;
  if (!seenBuckets.has(bucketKey)) {
    seenBuckets.add(bucketKey);
    bucketList.push({ substrate: row.substrate, categoryDescription: row.categoryDescription });
  }

  const substrate = String(row.substrate || '').trim();
  const categoryDescription = String(row.categoryDescription || '').trim();
  if (substrate && categoryDescription) {
    if (!categoriesBySubstrate.has(substrate)) {
      categoriesBySubstrate.set(substrate, new Set());
    }
    categoriesBySubstrate.get(substrate).add(categoryDescription);
  }

  const substrateKey = normalizeMappingText(row.substrate);
  if (substrateKey) {
    seenSubstrates.add(row.substrate);
  }
});

export const SUBSTRATE_EXCEL_BUCKETS = bucketList;

export const SUBSTRATE_EXCEL_TYPES = Array.from(seenSubstrates);

export const SUBSTRATE_EXCEL_CATEGORY_DESCRIPTIONS_BY_SUBSTRATE = Array.from(categoriesBySubstrate.entries())
  .sort((a, b) => a[0].localeCompare(b[0]))
  .reduce((acc, [substrate, values]) => {
    acc[substrate] = Array.from(values).sort((a, b) => a.localeCompare(b));
    return acc;
  }, {});

export const getCategoryDescriptionsForSubstrate = (substrate) => {
  const key = String(substrate || '').trim();
  if (!key) return [];
  return SUBSTRATE_EXCEL_CATEGORY_DESCRIPTIONS_BY_SUBSTRATE[key] || [];
};

export const resolveSubstrateMappingByDescription = (itemDescription) => {
  const key = normalizeMappingText(itemDescription);
  if (!key) return null;
  return mappingByItemDescription.get(key) || null;
};

export const isSubstratesCategory = (category) => normalizeMappingText(category) === 'substrates';

export const getMappedSubstrateDisplayFields = (row) => {
  if (!isSubstratesCategory(row?.category)) return null;
  const mapped = resolveSubstrateMappingByDescription(row?.maindescription || row?.item_name);
  if (!mapped) return null;
  return {
    substrate: mapped.substrate,
    categoryDescription: mapped.categoryDescription,
    itemDescription: mapped.itemDescription,
  };
};

export const getSubstrateDensityDefault = (substrate) => {
  const key = String(substrate || '').trim();
  if (!key) return null;
  return Object.prototype.hasOwnProperty.call(SUBSTRATE_DENSITY_BY_TYPE, key)
    ? SUBSTRATE_DENSITY_BY_TYPE[key]
    : null;
};
